import{_ as e,o as i,c as t,ae as s}from"./chunks/framework.Czhw_PXq.js";const g=JSON.parse('{"title":"gRPC","description":"","frontmatter":{},"headers":[],"relativePath":"framework/grpc.md","filePath":"framework/grpc.md","lastUpdated":1776574990000}'),r={name:"framework/grpc.md"};function o(p,a,l,n,c,d){return i(),t("div",null,[...a[0]||(a[0]=[s('<h1 id="grpc" tabindex="-1">gRPC <a class="header-anchor" href="#grpc" aria-label="Permalink to &quot;gRPC&quot;">​</a></h1><p>EasyYapi supports exporting API documentation from gRPC service implementations.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>gRPC support can automatically recognize gRPC service classes and extract:</p><ul><li>gRPC service path (<code>/&lt;package&gt;.&lt;ServiceName&gt;/&lt;MethodName&gt;</code>)</li><li>Streaming type (unary, server-streaming, client-streaming, bidirectional)</li><li>Request/response protobuf message types</li></ul><h2 id="enable-grpc-support" tabindex="-1">Enable gRPC Support <a class="header-anchor" href="#enable-grpc-support" aria-label="Permalink to &quot;Enable gRPC Support&quot;">​</a></h2><p>gRPC support is enabled by default. You can toggle it in IDE settings:</p><p><kbd>Settings</kbd> &gt; <kbd>Other Settings</kbd> &gt; <kbd>EasyApi</kbd></p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><h3 id="grpc-artifact-configs" tabindex="-1">gRPC Artifact Configs <a class="header-anchor" href="#grpc-artifact-configs" aria-label="Permalink to &quot;gRPC Artifact Configs&quot;">​</a></h3><p>Configure gRPC artifact coordinates for proto file resolution:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">grpc.artifact.configs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=com.example:my-proto:1.0.0</span></span></code></pre></div><h3 id="grpc-additional-jars" tabindex="-1">gRPC Additional Jars <a class="header-anchor" href="#grpc-additional-jars" aria-label="Permalink to &quot;gRPC Additional Jars&quot;">​</a></h3><p>Add additional JAR files for proto resolution:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">grpc.additional.jars</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/path/to/proto.jar</span></span></code></pre></div><h3 id="grpc-repositories" tabindex="-1">gRPC Repositories <a class="header-anchor" href="#grpc-repositories" aria-label="Permalink to &quot;gRPC Repositories&quot;">​</a></h3><p>Configure Maven repositories for artifact resolution:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">grpc.repositories</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=https://repo.maven.apache.org/maven2</span></span></code></pre></div><h3 id="grpc-call" tabindex="-1">gRPC Call <a class="header-anchor" href="#grpc-call" aria-label="Permalink to &quot;gRPC Call&quot;">​</a></h3><p>Enable gRPC call functionality to invoke gRPC methods directly from the IDE:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">grpc.call.enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true</span></span></code></pre></div><h2 id="class-recognition" tabindex="-1">Class Recognition <a class="header-anchor" href="#class-recognition" aria-label="Permalink to &quot;Class Recognition&quot;">​</a></h2><p>The <code>class.is.grpc</code> rule determines whether a class is a gRPC service:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class.is.grpc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.isExtend(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;io.grpc.stub.AbstractStub&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/guide/export-rpc">Export RPC Doc</a> — Exporting RPC documentation</li></ul>',26)])])}const u=e(r,[["render",o]]);export{g as __pageData,u as default};
